PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?title ?deadline WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAssignments ?child ; p:hasFreelance_Journalists ?parent . } GROUP BY ?child }
  ?child p:title ?title .
  ?child p:deadline ?deadline .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Freelance_Journalists } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?title ?deadline WHERE {
  ?article_publication a :Article_Publication .
  ?assignments a :Assignments .
  ?article_publication p:hasAssignments ?assignments .
  ?freelance_journalists a :Freelance_Journalists .
  ?article_publication p:hasFreelance_Journalists ?freelance_journalists .
  ?freelance_journalists p:name ?name .
  ?assignments p:title ?title .
  ?assignments p:deadline ?deadline .
} }
}

